import{_ as e,o as r,c as t,a as p}from"./app.7f9bd173.js";const d=JSON.parse('{"title":"拍照中的小技巧","description":"","frontmatter":{},"headers":[{"level":2,"title":"背景","slug":"背景","link":"#背景","children":[]},{"level":2,"title":"姿势","slug":"姿势","link":"#姿势","children":[]},{"level":2,"title":"构图","slug":"构图","link":"#构图","children":[]}],"relativePath":"PhotoTips/1.md"}'),a={name:"PhotoTips/1.md"},c=p('<h1 id="拍照中的小技巧" tabindex="-1">拍照中的小技巧 <a class="header-anchor" href="#拍照中的小技巧" aria-hidden="true">#</a></h1><p>喜欢拍照的大家，小编相信也喜欢拍人像照，因为可以把自己拍得美美哒，那么人像应该怎么拍才上镜好看呢。今天我们就来说说一些<a href="https://www.zhihu.com/search?q=%E4%BA%BA%E5%83%8F%E6%8B%8D%E7%85%A7&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A%22101075577%22%7D" target="_blank" rel="noreferrer">人像拍照</a>技巧，从背景、姿势、构图上来体现，大家都要掌握起来。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/620401f8925a468fa2d12a9b2466a840~tplv-k3u1fbpfcp-zoom-1.image" alt=""></p><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-hidden="true">#</a></h2><p><a href="https://www.zhihu.com/search?q=%E4%BA%BA%E5%83%8F%E7%85%A7&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A%22101075577%22%7D" target="_blank" rel="noreferrer">人像照</a>的背景，在小编看来，一定要足够的干净，因为背景干净简洁了才能更好的突出被拍伙伴的美，所以。一定要选择干净的背景或者开启长焦大光圈<a href="https://www.zhihu.com/search?q=%E8%99%9A%E5%8C%96&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A%22101075577%22%7D" target="_blank" rel="noreferrer">虚化</a>背景。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/12f617b7d65848d5bf4a14cac99c2cba~tplv-k3u1fbpfcp-zoom-1.image" alt=""></p><h2 id="姿势" tabindex="-1">姿势 <a class="header-anchor" href="#姿势" aria-hidden="true">#</a></h2><p>人像的姿势有很多选择，不过说到底无非都是要做到放松，自然，那么我们来说说几个比较常见的。</p><p><strong>1、和镜头互动</strong></p><p>和镜头互动，相比对着镜头静静地站着，可以让你看起来更加的放松自然，而且能增加画面的动感，拍照起来美美的。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/d8d2e0de338e4d0490b68fdfa986ce0d~tplv-k3u1fbpfcp-zoom-1.image" alt=""></p><p><strong>2、不看镜头</strong></p><p>很多人像照，摄影师为了拍得更加自然好看，都会让模特不要看镜头，因为，面对镜头，大家都不是经常拍照的明星没有那么强的镜头感，拍照就不自然了，不看的镜头的话反而会有更好的表现。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/9de99f5eee7844d0906c14ee259d7e6a~tplv-k3u1fbpfcp-zoom-1.image" alt=""></p><p><strong>3、利用肢体</strong></p><p>拍人像，除了表情，肢体的动作姿势也是很重要的一部分，比如可以利用你的双手动起来，给画面增加动感，让身体的状态更加的自然起来。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/b10126d21cd34e838b50b305d1f9393d~tplv-k3u1fbpfcp-zoom-1.image" alt=""></p><p><strong>4、特写</strong></p><p>人像的<a href="https://www.zhihu.com/search?q=%E7%89%B9%E5%86%99&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A%22101075577%22%7D" target="_blank" rel="noreferrer">特写</a>是拍人像必须拍的一个拍照姿势了，因为它能够最大程度的突出被拍者的魅力，只要把自己收拾得精致点，都可以拍出美美的人像照。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/35ce5eec1be14618b77d0b05401683f3~tplv-k3u1fbpfcp-zoom-1.image" alt=""></p><p><strong>5、微笑</strong></p><p>一个感的笑容，是很有感染力的，这就是为什么拍照的时候，很多摄影师都会叫大家笑一笑的原因，笑起来，你会发现没那么紧张，表情也舒展开来，拍照就自然好看了。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/97e78b4f83c24e419d42f3bbb72186da~tplv-k3u1fbpfcp-zoom-1.image" alt=""></p><p><strong>6、侧身</strong></p><p>侧身照是适合于任何拍照模式的，不管是旅行照、<a href="https://www.zhihu.com/search?q=%E8%89%BA%E6%9C%AF%E7%85%A7&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A%22101075577%22%7D" target="_blank" rel="noreferrer">艺术照</a>还是人像写真照，一个简单的侧身，就可以让你看起来更瘦更上镜，当你觉得把自己最美的一侧留给镜头了，你也就怎么拍都不怕了。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/0bbe71c6c741470abde45c8051051e7d~tplv-k3u1fbpfcp-zoom-1.image" alt=""></p><p><strong>7、借用小道具</strong></p><p>合理的利用身边的一些小道具，可以让你在面对镜头的时候会有更大的表现力，你会感觉你不是被拍照，而是在玩不经意被偷拍，这样的人像也就比较自然上镜了。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/7137a79bfb2e4764b3d6b53f718c7561~tplv-k3u1fbpfcp-zoom-1.image" alt=""></p><h2 id="构图" tabindex="-1"><a href="https://www.zhihu.com/search?q=%E6%9E%84%E5%9B%BE&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A%22101075577%22%7D" target="_blank" rel="noreferrer">构图</a> <a class="header-anchor" href="#构图" aria-hidden="true">#</a></h2><p>关于人像照的构图，其实也很简单，无非就是要突出人物，所以，大致的构图有以下几个。</p><p><strong>1、中心构图</strong></p><p>就是把人物放在画面中心，这样大家会把焦点关注在人像上，拍起来的照片，就会更加的彰显人像的美。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/0c9c70df36b6487494191b7513351292~tplv-k3u1fbpfcp-zoom-1.image" alt=""></p><p><strong>2、<a href="https://www.zhihu.com/search?q=%E4%B8%89%E8%A7%92%E5%BD%A2%E6%9E%84%E5%9B%BE&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A%22101075577%22%7D" target="_blank" rel="noreferrer">三角形构图</a></strong></p><p>人像经常用到的构图，就是三角形构图，特别是特写<a href="https://www.zhihu.com/search?q=%E5%85%A8%E8%BA%AB%E7%85%A7&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A%22101075577%22%7D" target="_blank" rel="noreferrer">全身照</a>的时候，会让模特摆一些姿势，让身体成为一个三角形的姿势，这样会把大家的眼光吸引到这个稳定的三角形，也就是模特的身上。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/d720f22536f84d9f984f346c48477fbe~tplv-k3u1fbpfcp-zoom-1.image" alt=""></p><p><strong>3、框架构图</strong></p><p>拍人像照的时候，很多摄影师喜欢利用一些生活的框架来突出人像，因为有一些框架的<a href="https://www.zhihu.com/search?q=%E5%85%83%E7%B4%A0&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A%22101075577%22%7D" target="_blank" rel="noreferrer">元素</a>在，可以把大家的关注点吸引到框架的后面，这样拍照就能突出模特的美了。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/005a6a84b8954c4cab537f7973b18a24~tplv-k3u1fbpfcp-zoom-1.image" alt=""></p><p>好啦，以上就是今天小编带来的人像拍照技巧啦，大家学好拍照背景、7个拍照姿势、3个拍照构图，掌握起来，就能拍美美的人像照啦。</p>',41),s=[c];function i(o,h,n,m,f,b){return r(),t("div",null,s)}const _=e(a,[["render",i]]);export{d as __pageData,_ as default};
